const KEY='optishield.settings';
const DEFAULT_SETTINGS={enabled:true,mode:'auto',intensity:32,jitter:26,edgeInstability:22,ocrDisruption:20,frequencyDisruption:18,adaptiveTemporalPhaseShifting:true,subpixelChromaDrift:true,edgeReconstructionPoisoning:true,compressionInterferencePatterns:true,debugPanel:false,reducedMotion:false,lowEyeStrain:true,dyslexiaFriendly:false,highContrastCompatible:true,disabledSites:[]};
const DEFAULT_STATS={fps:60,frameMs:16.7,droppedFrames:0,recommendedMode:'canvas2d',renderer:'auto',qualityScale:1,perturbationStrength:32,ocrResistance:38};
async function getSettings(){const r=await chrome.storage.local.get(KEY);return {...DEFAULT_SETTINGS,...(r[KEY]||{})};}
async function setSettings(patch){const next={...(await getSettings()),...patch};await chrome.storage.local.set({[KEY]:next});return next;}
function sendSettings(settings){chrome.runtime.sendMessage({type:'OPTISHIELD_SETTINGS_UPDATED',settings}).catch(()=>{});}
function slider(label,key,value,help=''){return `<label class="control"><span class="control-row"><span>${label}</span><strong id="v-${key}">${value}%</strong></span><input data-key="${key}" type="range" min="0" max="100" value="${value}">${help?`<small>${help}</small>`:''}</label>`;}
function check(label,key,checked){return `<label class="check"><input data-key="${key}" type="checkbox" ${checked?'checked':''}> ${label}</label>`;}
let settings=DEFAULT_SETTINGS;
function renderControls(){document.getElementById('enabled').textContent=settings.enabled?'On':'Off';document.getElementById('enabled').className=`toggle ${settings.enabled?'':'off'}`;document.getElementById('controls').innerHTML=`<label class="control"><span>Rendering mode</span><select data-key="mode"><option value="auto">Auto recommended</option><option value="canvas2d">Canvas 2D</option><option value="webgl">WebGL</option></select></label>${slider('Overall intensity','intensity',settings.intensity,'Higher values increase optical disruption but may become more visible.')}${slider('Subpixel jitter','jitter',settings.jitter)}${slider('Edge instability','edgeInstability',settings.edgeInstability)}${slider('OCR disruption','ocrDisruption',settings.ocrDisruption)}${slider('Frequency disruption','frequencyDisruption',settings.frequencyDisruption)}${check('Adaptive temporal phase shifting','adaptiveTemporalPhaseShifting',settings.adaptiveTemporalPhaseShifting)}${check('Subpixel chroma drift','subpixelChromaDrift',settings.subpixelChromaDrift)}${check('Edge reconstruction poisoning','edgeReconstructionPoisoning',settings.edgeReconstructionPoisoning)}${check('Compression interference patterns','compressionInterferencePatterns',settings.compressionInterferencePatterns)}${check('Low eye strain','lowEyeStrain',settings.lowEyeStrain)}${check('Reduced motion','reducedMotion',settings.reducedMotion)}${check('Dyslexia-friendly tuning','dyslexiaFriendly',settings.dyslexiaFriendly)}${check('Local debugging panel','debugPanel',settings.debugPanel)}`;document.querySelector('[data-key="mode"]').value=settings.mode;}
function showStats(s){document.getElementById('fps').textContent=s.fps;document.getElementById('frameMs').textContent=s.frameMs;document.getElementById('renderer').textContent=s.renderer;document.getElementById('quality').textContent=Math.round(s.qualityScale*100)+'%';document.getElementById('strength').textContent=s.perturbationStrength+'%';document.getElementById('ocr').textContent=s.ocrResistance+'%';}
document.addEventListener('input',async e=>{const el=e.target;if(!el.dataset?.key)return;const key=el.dataset.key;settings=await setSettings({[key]:el.type==='checkbox'?el.checked:el.type==='range'?Number(el.value):el.value});sendSettings(settings);if(el.type==='range')document.getElementById(`v-${key}`).textContent=el.value+'%';});
document.getElementById('enabled').addEventListener('click',async()=>{settings=await setSettings({enabled:!settings.enabled});sendSettings(settings);renderControls();});
chrome.runtime.onMessage.addListener(m=>{if(m.type==='OPTISHIELD_STATS')showStats(m.stats);});
(async()=>{settings=await getSettings();renderControls();const r=await chrome.runtime.sendMessage({type:'OPTISHIELD_GET_STATS'}).catch(()=>({stats:DEFAULT_STATS}));showStats(r?.stats||DEFAULT_STATS);})();
